fn render_swarm_text(value: &Value) -> String {
    match value {
        Value::Array(entries) => {
            if entries.is_empty() {
                return "no records".to_owned();
            }
            entries
                .iter()
                .map(|entry| {
                    if entry.get("kind").is_some() && entry.get("taskId").is_some() {
                        format_event_line(entry).unwrap_or_else(|| entry.to_string())
                    } else if entry.get("approvalId").is_some() {
                        format_approval_text(entry)
                    } else if entry.get("runId").is_some() {
                        format_run_text(entry)
                    } else if entry.get("artifactId").is_some() {
                        format_artifact_text(entry)
                    } else if entry.get("objectiveId").is_some() && entry.get("projectedStatus").is_some() {
                        format_objective_text(entry)
                    } else if entry.get("taskId").is_some() && entry.get("status").is_some() {
                        format_task_text(entry)
                    } else {
                        entry.to_string()
                    }
                })
                .collect::<Vec<_>>()
                .join("\n")
        }
        Value::Object(_) => {
            if let Some(event) = value.get("event") {
                let mut lines = vec![format_event_line(event).unwrap_or_else(|| event.to_string())];
                if let Some(task) = value.get("task") {
                    lines.push(format_task_text(task));
                }
                lines.join("\n")
            } else if value.get("approvalId").is_some() {
                format_approval_text(value)
            } else if value.get("runId").is_some() {
                format_run_text(value)
            } else if value.get("artifactId").is_some() {
                format_artifact_text(value)
            } else if value.get("objective").is_some() && value.get("tasks").is_some() {
                format_objective_status_text(value)
            } else if value.get("objectiveId").is_some() && value.get("action").is_some() {
                format_manager_next_text(value)
            } else if value.get("objectiveId").is_some() && value.get("projectedStatus").is_some() {
                format_objective_text(value)
            } else if value.get("taskId").is_some() && value.get("status").is_some() {
                format_task_text(value)
            } else {
                value.to_string()
            }
        }
        Value::String(text) => text.clone(),
        _ => value.to_string(),
    }
}

fn print_output(value: &Value, json_mode: bool) {
    if json_mode {
        println!("{value}");
    } else {
        println!("{}", render_swarm_text(value));
    }
}

fn fail(message: &str, json_mode: bool) -> ExitCode {
    if json_mode {
        println!("{}", json!({ "status": "error", "error": message }));
    } else {
        eprintln!("{message}");
    }
    ExitCode::from(1)
}

fn handle_event_command(
    json_mode: bool,
    root: &Path,
    task_id: &str,
    actor: &str,
    kind: &str,
    explicit_detail: &Option<String>,
) -> ExitCode {
    let (paths, mut connection) = match open_swarm_connection(root) {
        Ok(value) => value,
        Err(message) => return fail(&message, json_mode),
    };
    if kind == "lease_acquired" {
        let Some(task) = (match load_task_state(&connection, task_id) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        }) else {
            return fail(&format!("unknown swarm task `{task_id}`"), json_mode);
        };
        let (ready, lease_expired, blocked, _, _) = match task_ready_state(&connection, &task, now_ms()) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        };
        if !ready {
            return fail(&format!("swarm task `{task_id}` is not ready: {}", blocked.join("; ")), json_mode);
        }
        if (task.status == "leased" || task.status == "active") && !lease_expired {
            return fail(&format!("swarm task `{task_id}` already has an active lease"), json_mode);
        }
    }
    let detail = explicit_detail
        .clone()
        .unwrap_or_else(|| task_detail_for_kind(kind, task_id));
    let event = SwarmEvent {
        kind: kind.to_owned(),
        task_id: task_id.to_owned(),
        actor: actor.to_owned(),
        detail,
        at_ms: now_ms(),
        payload_json: "{}".to_owned(),
    };
    let task = match append_event(&mut connection, &event) {
        Ok(task) => task,
        Err(message) => return fail(&message, json_mode),
    };
    let rendered_task = match task_record_json(&connection, &task) {
        Ok(value) => value,
        Err(message) => return fail(&message, json_mode),
    };
    print_output(&swarm_event_output(&paths, &event, rendered_task), json_mode);
    ExitCode::SUCCESS
}

fn handle_query_command(json_mode: bool, command: SwarmCommand) -> ExitCode {
    let root = match &command {
        SwarmCommand::Status { root, .. }
        | SwarmCommand::History { root, .. }
        | SwarmCommand::Tasks { root }
        | SwarmCommand::Summary { root }
        | SwarmCommand::Tail { root, .. }
        | SwarmCommand::Runs { root, .. }
        | SwarmCommand::ObjectiveStatus { root, .. }
        | SwarmCommand::Objectives { root }
        | SwarmCommand::Ready { root, .. }
        | SwarmCommand::Approvals { root, .. }
        | SwarmCommand::Artifacts { root, .. }
        | SwarmCommand::ManagerNext { root, .. } => root,
        _ => unreachable!(),
    };
    let (_paths, connection) = match open_swarm_connection(root) {
        Ok(value) => value,
        Err(message) => return fail(&message, json_mode),
    };
    let value = match command {
        SwarmCommand::Status { task_id, .. } => {
            match load_task_state(&connection, &task_id) {
                Ok(Some(task)) => match task_record_json(&connection, &task) {
                    Ok(value) => value,
                    Err(message) => return fail(&message, json_mode),
                },
                Ok(None) => match task_record_json(&connection, &empty_task_state(&task_id, 0)) {
                    Ok(value) => value,
                    Err(message) => return fail(&message, json_mode),
                },
                Err(message) => return fail(&message, json_mode),
            }
        }
        SwarmCommand::History { task_id, .. } => match history_json(&connection, &task_id) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Tasks { .. } => match tasks_json(&connection) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::ObjectiveStatus { objective_id, .. } => match objective_status_json(&connection, &objective_id) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Objectives { .. } => match objectives_json(&connection) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Ready { objective_id, .. } => match ready_json(&connection, objective_id.as_deref()) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Summary { .. } => match summary_json(&connection) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Tail { task_id, limit, .. } => match tail_json(&connection, task_id.as_deref(), limit) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Runs { task_id, .. } => match runs_json(&connection, task_id.as_deref()) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Artifacts { task_id, .. } => match artifacts_json(&connection, task_id.as_deref()) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::Approvals { task_id, .. } => match approvals_json(&connection, task_id.as_deref()) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        SwarmCommand::ManagerNext { objective_id, .. } => match manager_next_json(&connection, &objective_id) {
            Ok(value) => value,
            Err(message) => return fail(&message, json_mode),
        },
        _ => unreachable!(),
    };
    print_output(&value, json_mode);
    ExitCode::SUCCESS
}

